module watchdog(
    input clk,       // 100MHz clock signal
    input wdt_sig,   // input signal to be monitored
    output reg watchdog_out   // output signal
);

reg [20:0] count = 0;  // counter to measure 5ms interval
reg prev_signal = 0;   // previous input signal value

always @(posedge clk) begin
    if (wdt_sig != prev_signal) begin
        count <= 0;   // reset counter if input signal toggles
        watchdog_out <= 1;
    end else if (count < 500000) begin
        count <= count + 1;   // increment counter every clock cycle
    end else begin
        count <= 0;   // reset counter if 5ms interval has elapsed
        watchdog_out <= 0;      // turn off output signal if no toggling within 5ms
    end

    prev_signal <= wdt_sig;  // update previous signal value

end

endmodule

`timescale 1ns / 1ps

module quadDecoder #(parameter WIDTH=16) (
    input enc_a,
    input enc_b,
    input clear,
    input clk,
    input en,
    output [WIDTH-1:0] count
);

reg A, B, A_FF, B_FF;

// negative logic for encoders
assign neg_enc_a = ~enc_a;
assign neg_enc_b = ~enc_b;

// if A is active now, but B was active last clock cycle, moving up...
assign counter_up = A ^ B_FF;

// if B is active now, but A was active last clock cycle, moving up...
assign counter_down = B ^ A_FF;

// counter increments or decrements if the encoder is moving, and decoder is enabled
assign counter_en = (counter_up ^ counter_down) && en;

// flopping input signals
always @(posedge clk)
begin
     A <= neg_enc_a; 
     B <= neg_enc_b; 
     A_FF <= A; 
     B_FF <= B; 
end 

// Count the reletive position of the encoders with a counter
cntr_udclr_nb #(.n(WIDTH)) cntr (
    .clk(clk),
    .clr(clear),
    .up(counter_up),
    .dn(counter_down),
    .en(counter_en),
    .ld(0),
    .D(0),
    .count(count)
);

endmodule

`ifndef MOTOR_CONTROLLER_SIGNALS_VH
`define MOTOR_CONTROLLER_SIGNALS_VH
// defining feild widths AXI->driver
parameter MOTOR_DUTY_IN_WIDTH   = 8;
parameter CLK_DIV_WIDTH         = 3;

// defining field widths driver->AXI
parameter MOTOR_POS_WIDTH       = 16;

// defining slice inputs from AXI->DRIVER
// h-brige inputs
parameter MOTOR_DUTY_IN_START   = 0;
parameter MOTOR_DUTY_IN_END     = MOTOR_DUTY_IN_START + (MOTOR_DUTY_IN_WIDTH - 1); // 7
parameter CLK_DIV_START         = MOTOR_DUTY_IN_END + 1;   // 8  
parameter CLK_DIV_END           = CLK_DIV_START + (CLK_DIV_WIDTH - 1); // 10
parameter MOTOR_DIR_IDX         = CLK_DIV_END + 1;      // 11
parameter H_BRIDGE_EN_IDX       = MOTOR_DIR_IDX + 1;    // 12
// quad-decoder inputs
parameter DEC_CLR_IDX           = H_BRIDGE_EN_IDX + 1;        // 13
parameter DEC_EN_IDX            = DEC_CLR_IDX + 1;      // 14

parameter CNTRL_VEC_WIDTH          = DEC_EN_IDX;
`endif

`timescale 1ns / 1ps
//////////////////////////////////////////////////////////////////////////////////
// Company:   Ratner Surf Designs
// Engineer:  James Ratner
// 
// Create Date: 07/04/2018 02:46:31 PM
// Design Name: 
// Module Name: cntr_udclr_nb
// Project Name: 
// Target Devices: 
// Tool Versions: 
// Description: Generic n-bit up/down counter with asynchronous reset. 
//     This counter also has RCO that works for both up & down counting. 
// 
//      cntr_udclr_nb #(.n(16)) MY_CNTR (
//          .clk   (xxxx), 
//          .clr   (xxxx), 
//          .up    (xxxx), 
//          .ld    (xxxx), 
//          .D     (xxxx), 
//          .count (xxxx), 
//          .rco   (xxxx)   ); 
//
// Dependencies: 
// 
// Revision:
// Revision (07-06-2018) 1.00 - File Created 
//          (11-11-2018) 1.01 - fixed RCO to blocking assignments
//          (11-14-2018) 1.02 - fixed RCO output error 
//                                  changed file name 
//          (12-20-2020) 1.05 - changed parameter location & comments
//
// Additional Comments:
// 
//////////////////////////////////////////////////////////////////////////////////

module cntr_udclr_nb  #(parameter n=8) (clk, clr, up, dn, en, ld, D, count, rco); 
    input  clk, clr, up, dn, en, ld; 
    input  [n-1:0] D; 
    output   reg [n-1:0] count; 
    output   reg rco; 


    always @(posedge clr, posedge clk)
    begin 
        if (clr == 1)       // asynch reset
           count <= 0;
        else if (ld == 1)   // load new value
           count <= D; 
        else if (en == 1)
            begin
                if (up == 1)   // count up (increment)
                    count <= count + 1; 
                else if (dn == 1)   // count down (decrement)
                    count <= count - 1; 
           end 
    end 


    //- handles the RCO, which is direction dependent
    always @(count, up)
    begin 
       if ( up == 1 && &count == 1'b1)
          rco = 1'b1;
       else if (up == 0 && |count == 1'b0)
          rco = 1'b1;
       else 
          rco = 1'b0; 
    end

endmodule

`timescale 1ns / 1ps

module H_Bridge_Driver(
    input clk,
    input [7:0] duty_in,
    input [2:0] clk_divisor,
    input dir,
    input en,

    output out1,
    output out2
    );

    wire pwm;

    PWM_Generator pwm_gen(
        .clk (clk), 
        .duty_in (duty_in),
        .clk_divisor (clk_divisor),
        .en (en),
        .pwm (pwm)
       );

    assign out1 = ((~pwm) | dir) & en;
    assign out2 = ~(pwm & dir) & en;

endmodule

